async function main() {
  console.log('🚀 「ワイフコレクション」の店舗とセラピスト一括登録を開始します...\n');

  try {
    console.log('🏪 店舗データを登録中...');
    
    const SHOP_DATA = {
      id: SHOP_ID,
      name: 'ワイフコレクション',
      area_id: AREA_ID, // tokyo_sumida_kinshicho
      group_id: GROUP_ID, 
      schedule_url: 'https://fujoho.jp/index.php?p=shop_info&id=60829&h=ON',
      website_url: 'https://www.wife-collection.com/',
      business_hours: '営業時間要確認', 
      price_system: '60分 12,000円～', // 画像から反映
      image_url: 'https://placehold.jp/3498db/ffffff/400x300.png?text=%E3%83%AF%E3%82%A4%E3%83%95%E3%82%B3%E3%83%AC%E3%82%AF%E3%82%B7%E3%83%A7%E3%83%B3',
      raw_data: {
        prefecture: '東京都',
        city: '墨田区',
        area: '錦糸町',
        address: '東京都墨田区錦糸町エリア',
        system: [
          {
            courseName: '通常コース',
            description: '画像から読み取った料金です',
            prices: [
              { time: '60min', price: '12,000円' },
              { time: '90min', price: '16,000円' },
              { time: '120min', price: '20,000円' },
              { time: '150min', price: '24,000円' }
            ]
          },
          {
            courseName: 'ANNEXコース',
            description: '画像から読み取った料金です',
            prices: [
              { time: '75min', price: '16,000円' },
              { time: '100min', price: '20,000円' },
              { time: '130min', price: '26,000円' }
            ]
          }
        ]
      }
    };

    const { error: upsertErr } = await supabase.from('shops').upsert(SHOP_DATA, { onConflict: 'id' });
    if (upsertErr) throw upsertErr;
    console.log(`✅ 店舗情報（ID: ${SHOP_ID}）を登録しました。\n`);

    console.log(`⏳ HTMLからセラピストを抽出中...`);
    const $ = cheerio.load(HTML_CONTENT);
    const items = $('.cs_li');

    let newTherapists = [];
    const now = new Date().toISOString();
    const seenNames = {}; 

    items.each((_, el) => {
      const item = $(el);
      
      let nameWithAge = item.find('.cs_name').text().trim(); // 例: "冴木もえ(36歳)"
      if (!nameWithAge) return;

      // 名前の抽出（年齢部分を除去）
      const nameMatch = nameWithAge.match(/^([^\(]+)/);
      const cleanName = nameMatch ? nameMatch[1].trim() : nameWithAge;
      
      // 年齢の抽出
      const ageMatch = nameWithAge.match(/\((\d+)歳\)/);
      const age = ageMatch ? `${ageMatch[1]}歳` : '';

      let finalNameId = cleanName.replace(/\s/g, '_');
      if (seenNames[finalNameId]) {
        seenNames[finalNameId]++;
        finalNameId = `${finalNameId}_${seenNames[finalNameId]}`; 
      } else {
        seenNames[finalNameId] = 1;
      }
      
      let imageUrl = item.find('.cs_ph img').attr('src') || '';
      if (imageUrl && !imageUrl.startsWith('http')) {
          imageUrl = `${BASE_URL}${imageUrl}`;
      }

      // サイズや勤務時間の抽出
      const sizeText = item.find('.cs_size').text().trim();
      const workTime = item.find('.cs_time').text().trim();
      
      let fullBio = '';
      if (age) fullBio += `年齢: ${age}\n`;
      if (sizeText) fullBio += `サイズ: ${sizeText}\n`;
      if (workTime) fullBio += `本日の出勤: ${workTime}`;

      // 新人タグの判定
      const isNew = item.find('.cs_new').length > 0;
      const tags = [];
      if(isNew) tags.push('新人');

      newTherapists.push({
        id: `${SHOP_ID}_${finalNameId}`,
        shop_id: SHOP_ID,
        name: cleanName, 
        image_url: imageUrl,
        is_active: true,
        last_seen_at: now,
        raw_data: {
          tags: tags,
          bio: fullBio.trim(),
          original_name: nameWithAge
        }
      });
    });

    console.log(`✅ ${newTherapists.length} 名のセラピストデータを抽出しました。`);

    console.log(`🗑️ 古いセラピストデータをクリアしています...`);
    await supabase.from('therapists').delete().eq('shop_id', SHOP_ID);

    console.log(`📦 新しいデータを登録中...`);
    const chunkSize = 100;
    for (let i = 0; i < newTherapists.length; i += chunkSize) {
      const chunk = newTherapists.slice(i, i + chunkSize);
      const { error: insertError } = await supabase.from('therapists').insert(chunk);
      if (insertError) throw insertError;
    }

    console.log(`\n🎉 登録完了！「ワイフコレクション」に店舗と ${newTherapists.length}名のセラピストがフル登録されました。`);
    console.log('ブラウザの「錦糸町」エリアでスーパーリロードしてご確認ください。');

  } catch (err) {
    console.error('❌ エラーが発生しました:', err.message);
  }
}

main();
